@module keyDispatch  src=keyDispatch.lua  loc=86  sha=65573d0  mode=namespace  self=keyDispatch

# Invariants & contracts
  @contract  returns early (no dispatch) when state.suppressKbd or not state.acceptCmds  @ 44
  @contract  state.pageSuppressed shrinks the walk to the root keymap only — body-region editors (swing, tuning) suppress page bindings without shadowing globals like playPause/quit  @ 45
  @contract  first-hit wins; false declines, releases the key, and lets the page char queue see it  @ 46
  @contract  while cmgr:isPrefixActive(), digits and '/' are captured (no dispatch); Esc cancels; any other key freezes the prefix and falls through to the keychain walk so commands can consumePrefix()  @ 47

# Shapes
  @shape  dispatchResult = { consumed: bool, commandHeld: { [imguiKey]=true } } — commandHeld holds keys down AND command-bound for the live chord  @ 43

# Imports
  @const ImGui = 'imgui'  @ 9

# Module-level constants
  @const keyDispatch = {}  @ 11

# Private functions
  @fn isDigitMods(mods)  @ 22-24
      -- Capture digits and '/' into the prefix buffer; Esc cancels. Returns
      -- 'consumed' if a prefix-accumulating key fired this frame; nil otherwise
      -- (so the normal keychain walk proceeds). The prefix is NOT finished here
      -- on fall-through: dispatchKeys calls finishPrefix only at the moment a
      -- bound command is about to fire, so idle frames don't kill the buffer.
      -- In prefix mode, digit keys count even with Ctrl/Super held: holding the
      -- chord open while typing a count is a natural reach, and any Ctrl-N or
      -- Super-N command binding is overridden for the duration of prefix mode.
      -- Shift/Alt still disqualify (Shift-digit emits a different char).
  @fn handlePrefixCapture(cmgr, ctx)  @ 26-41

# Public API (keyDispatch.*)
  @api keyDispatch.dispatchKeys(state, cmgr, ctx)  @ 48-84

# Uses (outbound edges)
  @use call    ImGui.GetKeyMods  @ handlePrefixCapture:28 dispatchKeys:57
  @use call    ImGui.IsKeyDown  @ dispatchKeys:64
  @use call    ImGui.IsKeyPressed  @ handlePrefixCapture:30,34,37 dispatchKeys:67
  @use require imgui  @ 9

# REAPER API surface
  @reaper ImGui_GetBuiltinPath
  @reaper MB

